1	type Item = { type: string };
2	type Scenario = { steps: Array<{ op: string; items: Array<Item> }> };
3	
4	const PROCESSING_FEE = 5;
5	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	function withFirstInsuranceSurcharge(basePremium: number): number {
17	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
18	}
19	
20	function quoteItem(item: Item): number {
21	  return withFirstInsuranceSurcharge(BASE_PREMIUMS[item.type]);
22	}
23	
24	const COMPONENT_TYPES = ["rune", "moonstone"];
25	const BLOCK_OF_THREE_BASE = 60;
26	
27	function countByType(items: Array<Item>): Record<string, number> {
28	  const counts: Record<string, number> = {};
29	  for (const item of items) {
30	    counts[item.type] = (counts[item.type] ?? 0) + 1;
31	  }
32	  return counts;
33	}
34	
35	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
36	  const { steps } = scenario as Scenario;
37	  const items = steps[0].items;
38	  const counts = countByType(items);
39	
40	  let itemsPremium = 0;
41	  const bundledTypes = new Set<string>();
42	  for (const componentType of COMPONENT_TYPES) {
43	    if (counts[componentType] === 3) {
44	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
45	      bundledTypes.add(componentType);
46	    }
47	  }
48	
49	  for (const item of items) {
50	    if (bundledTypes.has(item.type)) continue;
51	    itemsPremium += quoteItem(item);
52	  }
53	
54	  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
55	  return { results: [{ premium }] };
56	}
