it("should not mix component types when forming a block of 3", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
      },
